module RefModule(blank, hcount, vcount, moonX, moonY, moon);input blank;
	input signed [10:0] hcount, vcount;
	input signed [11:0] moonX, moonY;
	output moon;



  wire temp1_~blank = ~blank;
  wire temp2_(((hcount-moonX)*(hcount-moonX) + (vcount-moonY)*(vcount-moonY)) <= 1224) = (((hcount-moonX)*(hcount-moonX) + (vcount-moonY)*(vcount-moonY)) <= 1224);
  assign moon = temp1_~blank & temp2_(((hcount-moonX)*(hcount-moonX) + (vcount-moonY)*(vcount-moonY)) <= 1224);






endmodule
